fn count_valid_substrings(s: &str, star_positions: &[i64]) -> i64 {
    let n = s.len();
    let mut count = 0;
    let mut stars: Vec<i64> = star_positions.to_vec();

    stars.sort();

    for &pos in &stars {
        let mut left = pos;
        let mut right = pos;
        let mut current_count = 0;

        while left >= 0 && right < n {
            if s[right as usize] == '*' {
                current_count += right - left + 1;
                right += 1;
            } else {
                break;
            }
            left -= 1;
        }

        count += current_count;
    }

    count
